//! FOiL Mersenne hot path — certified strength reductions.
//!
//! Runtime side of gnosis-math `Gnosis/FoilMersenneHotPath.lean` (plan:
//! `distributed-inference/FOIL_HOTPATH_MERSENNE_PLAN.md`). The Griess band
//! decomposition `196884 = 300 + 98280 + 98304` gives every modulus FOiL takes
//! on its critical path Mersenne (`7 = 2³−1`, `4095 = 2¹²−1`, `8191 = 2¹³−1`)
//! or power-of-two (`8192 = 2¹³`) shape, so each primitive here replaces a
//! division with shift + mask + fold, and the allocated `format!` cache keys
//! with an injective packed integer key. Every function cites the Lean theorem
//! that makes the rewrite a *certified-equivalent* refactor; only profitability
//! is left to the benches (`bench-foil-entropy-ramp`, `bench-hope-jar-e8`).

/// Lean theorem IDs backing this module (gnosis-math
/// `Gnosis.FoilMersenneHotPath`, geometry from `Gnosis.GriessAeonMeshDescent`).
pub const FOIL_MERSENNE_HOT_PATH_THEOREM_IDS: [&str; 13] = [
    "Gnosis.FoilMersenneHotPath.mersenne_mod_fold",
    "Gnosis.FoilMersenneHotPath.fano_mod7_fold",
    "Gnosis.FoilMersenneHotPath.pair_band_mod_fold",
    "Gnosis.FoilMersenneHotPath.griess_mersenne_mod_fold",
    "Gnosis.FoilMersenneHotPath.frame_arena_mask",
    "Gnosis.FoilMersenneHotPath.frame_arena_shift",
    "Gnosis.FoilMersenneHotPath.frame_arena_geometry",
    "Gnosis.FoilMersenneHotPath.packKey_unpack_phase",
    "Gnosis.FoilMersenneHotPath.packKey_unpack_block",
    "Gnosis.FoilMersenneHotPath.packKey_unpack_band",
    "Gnosis.FoilMersenneHotPath.packKey_lt",
    "Gnosis.FoilMersenneHotPath.aeon_split_roundtrip",
    "Gnosis.FoilMersenneHotPath.foil_hot_path_certified",
];

// ─── 1. The Mersenne fold: division-free `mod (2^e − 1)` ────────────────────

/// `x % (2^e − 1)` with no `div` µop: iterate the certified fold
/// `x % (2^e − 1) = ((x >> e) + (x & (2^e − 1))) % (2^e − 1)` (Lean:
/// `mersenne_mod_fold`) until the value drops to the modulus or below, then
/// map the fixed point `2^e − 1 ≡ 0`. Each iteration subtracts
/// `(2^e − 1)·(x >> e)`, so the loop strictly descends and converges in
/// ≲ ⌈64/e⌉ steps worst case (~3 typical for hash-distributed input).
#[inline(always)]
pub const fn mersenne_fold_mod(x: u64, e: u32) -> u64 {
    debug_assert!(e >= 1 && e <= 63);
    let m = (1u64 << e) - 1;
    let mut x = x;
    while x > m {
        x = (x >> e) + (x & m); // each step certified: mersenne_mod_fold
    }
    if x == m {
        0 // the fold can land on 2^e − 1 ≡ 0
    } else {
        x
    }
}

/// The Fano router fold: `hash % 7` (`7 = 2³ − 1` Fano points) without a
/// division, for the `pump_entropy` query-hash → Fano-point projection.
/// Lean: `fano_mod7_fold`. Always returns a value in `0..7`.
#[inline(always)]
pub const fn fano_point_of_hash(hash: u64) -> u8 {
    mersenne_fold_mod(hash, 3) as u8
}

/// The pair-band fold: `x % 4095` (`4095 = 2¹² − 1`, the pair-band quantum
/// from `pairBand = 24·4095`). Lean: `pair_band_mod_fold`.
#[inline(always)]
pub const fn mod_pair_band_4095(x: u64) -> u64 {
    mersenne_fold_mod(x, 12)
}

/// The Griess–Mersenne fold: `x % 8191` (`8191 = 2¹³ − 1`, prime — good
/// distribution when hashing into the fused pair+frame carrier).
/// Lean: `griess_mersenne_mod_fold`.
#[inline(always)]
pub const fn mod_griess_prime_8191(x: u64) -> u64 {
    mersenne_fold_mod(x, 13)
}

// ─── 2. The mask-indexed frame arena ─────────────────────────────────────────

/// The frame band tiles exactly `2¹³ = 8192` Aeon blocks
/// (Lean: `frame_arena_geometry`).
pub const FRAME_ARENA_BLOCKS: u32 = 1 << 13;

/// Band seams in Aeon-block coordinates: the Sym² band ends at block 25, the
/// pair band at block `8215 = 25 + 8190`, and the whole carrier spans
/// `16407 = 8215 + 2¹³` blocks (Lean: `frame_arena_geometry`). Band dispatch
/// is therefore two unsigned compares.
pub const SYM_SQUARE_SEAM_BLOCK: u32 = 25;
pub const PAIR_FRAME_SEAM_BLOCK: u32 = 8215;
pub const MONSTER_AEON_BLOCKS: u32 = PAIR_FRAME_SEAM_BLOCK + FRAME_ARENA_BLOCKS;

/// Band seams in Monster-column coordinates (`block · 12`). Both seams alias
/// to Aeon phase 0 (Lean: `GriessAeonMeshDescent.band_boundaries_alias_to_phase_zero`),
/// so sharding the 196884-column carrier here never splits a phase block and
/// seam-pair gates are provably `none` — zero cross-shard gate traffic. Use
/// this layout if the `FOIL_ASYNC_LOSER_WORKERS` are ever sharded by band.
pub const SYM_SQUARE_SEAM_COLUMN: u32 = SYM_SQUARE_SEAM_BLOCK * 12;
pub const PAIR_FRAME_SEAM_COLUMN: u32 = PAIR_FRAME_SEAM_BLOCK * 12;

/// `k % 8192` as a single AND (Lean: `frame_arena_mask`).
#[inline(always)]
pub const fn frame_arena_block(k: u64) -> u64 {
    k & (FRAME_ARENA_BLOCKS as u64 - 1)
}

/// `k / 8192` as a single shift (Lean: `frame_arena_shift`).
#[inline(always)]
pub const fn frame_arena_page(k: u64) -> u64 {
    k >> 13
}

// ─── 3. The packed key: replaces `format!` string cache keys ────────────────

/// Band tags for [`pack_foil_key`]: Sym² | pair | frame (band-major carrier
/// layout). Bands count `3 < 4`, so 2 bits suffice (Lean: `packKey_covers_carrier`).
pub const FOIL_BAND_SYM_SQUARE: u32 = 0;
pub const FOIL_BAND_PAIR: u32 = 1;
pub const FOIL_BAND_FRAME: u32 = 2;

/// The packed FOiL key: `(band << 17) | (block << 4) | phase`. With the field
/// bounds (`band < 4`, `block < 2¹³`, `phase < 16`) the fields occupy disjoint
/// bits, so the ORs equal the additions in the Lean `packKey` definition. The
/// key fits in 19 bits (Lean: `packKey_lt`) — a `u32` with 13 bits of headroom,
/// or the low word of a `u64` with e.g. a Fibonacci index in the high word.
/// Hash = identity or one multiply, equality = one `cmp` instead of `memcmp`.
#[inline(always)]
pub const fn pack_foil_key(band: u32, block: u32, phase: u32) -> u32 {
    debug_assert!(band < 4);
    debug_assert!(block < 1 << 13);
    debug_assert!(phase < 16);
    (band << 17) | (block << 4) | phase
}

/// One AND recovers the Aeon phase (Lean: `packKey_unpack_phase`).
#[inline(always)]
pub const fn foil_key_phase(key: u32) -> u32 {
    key & 15
}

/// One shift + one AND recover the arena block (Lean: `packKey_unpack_block`).
#[inline(always)]
pub const fn foil_key_block(key: u32) -> u32 {
    (key >> 4) & 8191
}

/// One shift recovers the band (Lean: `packKey_unpack_band`).
#[inline(always)]
pub const fn foil_key_band(key: u32) -> u32 {
    key >> 17
}

/// Band of an Aeon block: two unsigned compares against the certified seams
/// (Lean: `frame_arena_geometry`).
#[inline(always)]
pub const fn monster_band_of_block(block: u32) -> u32 {
    if block < SYM_SQUARE_SEAM_BLOCK {
        FOIL_BAND_SYM_SQUARE
    } else if block < PAIR_FRAME_SEAM_BLOCK {
        FOIL_BAND_PAIR
    } else {
        FOIL_BAND_FRAME
    }
}

/// Address a Monster column of the 196884 carrier as a packed
/// `(band, blockInBand, phase)` key. The one `/ 12` + `% 12` pair here is the
/// ingest split the no-mod Aeon layout licenses (Lean: `aeon_split_roundtrip`
/// — lossless, phase bounded); after this, the hot path unpacks fields with
/// shift/mask only and never re-derives `% 12`.
#[inline(always)]
pub const fn monster_column_foil_key(column: u32) -> u32 {
    debug_assert!(column < MONSTER_AEON_BLOCKS * 12);
    let block = column / 12;
    let phase = column % 12;
    let band = monster_band_of_block(block);
    let block_in_band = match band {
        FOIL_BAND_SYM_SQUARE => block,
        FOIL_BAND_PAIR => block - SYM_SQUARE_SEAM_BLOCK,
        _ => block - PAIR_FRAME_SEAM_BLOCK,
    };
    pack_foil_key(band, block_in_band, phase)
}

// ─── 4. The no-mod Aeon layout ───────────────────────────────────────────────

/// An Aeon column stored as its lossless `(block, phase)` split (Lean:
/// `aeon_split_roundtrip`). Split once at ingest with [`Self::from_tick`];
/// afterwards [`Self::tick`] advances the phase with a compare-and-reset and
/// the hot path never computes `% 12` at all.
#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
pub struct AeonPhaseClock {
    pub block: u64,
    pub phase: u8,
}

impl AeonPhaseClock {
    /// The ingest split: `tick = 12·block + phase` with `phase < 12`
    /// (Lean: `aeon_split_roundtrip`). The only div/mod in the lifecycle.
    #[inline(always)]
    pub const fn from_tick(tick: u64) -> Self {
        Self {
            block: tick / 12,
            phase: (tick % 12) as u8,
        }
    }

    /// Advance one tick: compare-and-reset, no `% 12`.
    #[inline(always)]
    pub const fn tick(self) -> Self {
        let phase = self.phase + 1;
        if phase == 12 {
            Self {
                block: self.block + 1,
                phase: 0,
            }
        } else {
            Self {
                block: self.block,
                phase,
            }
        }
    }

    /// The exact inverse of the split: `12·block + phase`.
    #[inline(always)]
    pub const fn as_tick(self) -> u64 {
        self.block * 12 + self.phase as u64
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// A cheap deterministic 64-bit generator (splitmix64) for equivalence
    /// sweeps without pulling in a rand dependency.
    fn splitmix64(state: &mut u64) -> u64 {
        *state = state.wrapping_add(0x9e37_79b9_7f4a_7c15);
        let mut z = *state;
        z = (z ^ (z >> 30)).wrapping_mul(0xbf58_476d_1ce4_e5b9);
        z = (z ^ (z >> 27)).wrapping_mul(0x94d0_49bb_1331_11eb);
        z ^ (z >> 31)
    }

    #[test]
    fn mersenne_fold_matches_division_mod() {
        // Exhaustive on the small edge cases, randomized across the range.
        for x in 0..100_000u64 {
            assert_eq!(fano_point_of_hash(x) as u64, x % 7, "x = {x}");
            assert_eq!(mod_pair_band_4095(x), x % 4095, "x = {x}");
            assert_eq!(mod_griess_prime_8191(x), x % 8191, "x = {x}");
        }
        let mut state = 0xfeed_beef_u64;
        for _ in 0..100_000 {
            let x = splitmix64(&mut state);
            assert_eq!(fano_point_of_hash(x) as u64, x % 7, "x = {x}");
            assert_eq!(mod_pair_band_4095(x), x % 4095, "x = {x}");
            assert_eq!(mod_griess_prime_8191(x), x % 8191, "x = {x}");
        }
        // The fixed-point edge: multiples and near-multiples of the modulus.
        for m in [7u64, 4095, 8191] {
            let e = match m {
                7 => 3,
                4095 => 12,
                _ => 13,
            };
            for k in [0u64, 1, 2, 1_000_003] {
                for delta in 0..3u64 {
                    let x = m.wrapping_mul(k).wrapping_add(delta);
                    assert_eq!(mersenne_fold_mod(x, e), x % m, "x = {x}, m = {m}");
                }
            }
            assert_eq!(mersenne_fold_mod(u64::MAX, e), u64::MAX % m);
        }
    }

    #[test]
    fn frame_arena_mask_and_shift_match_div_mod() {
        let mut state = 0xa11c_e000_u64;
        for _ in 0..100_000 {
            let k = splitmix64(&mut state);
            assert_eq!(frame_arena_block(k), k % 8192);
            assert_eq!(frame_arena_page(k), k / 8192);
        }
        assert_eq!(frame_arena_block(u64::MAX), u64::MAX % 8192);
        assert_eq!(frame_arena_page(u64::MAX), u64::MAX / 8192);
    }

    #[test]
    fn frame_arena_geometry_constants() {
        // Lean: frame_arena_geometry — seams at 25 and 8215, carrier 16407
        // blocks, and 16407 · 12 = 196884 (the Griess dimension).
        assert_eq!(SYM_SQUARE_SEAM_BLOCK, 25);
        assert_eq!(PAIR_FRAME_SEAM_BLOCK, 8215);
        assert_eq!(MONSTER_AEON_BLOCKS, 16_407);
        assert_eq!(MONSTER_AEON_BLOCKS * 12, 196_884);
        // band_boundaries_alias_to_phase_zero: both column seams are phase 0.
        assert_eq!(SYM_SQUARE_SEAM_COLUMN, 300);
        assert_eq!(PAIR_FRAME_SEAM_COLUMN, 98_580);
        assert_eq!(SYM_SQUARE_SEAM_COLUMN % 12, 0);
        assert_eq!(PAIR_FRAME_SEAM_COLUMN % 12, 0);
    }

    #[test]
    fn packed_key_roundtrips_and_fits_19_bits() {
        for band in 0..4u32 {
            for block in [0u32, 1, 24, 25, 4095, 8190, 8191] {
                for phase in 0..16u32 {
                    let key = pack_foil_key(band, block, phase);
                    assert_eq!(foil_key_phase(key), phase); // packKey_unpack_phase
                    assert_eq!(foil_key_block(key), block); // packKey_unpack_block
                    assert_eq!(foil_key_band(key), band); // packKey_unpack_band
                    assert!(key < 1 << 19); // packKey_lt
                }
            }
        }
    }

    #[test]
    fn monster_column_key_is_injective_and_band_correct() {
        // Walk the whole carrier once: every Monster column has a distinct
        // packed address whose unpacked fields invert the ingest split.
        let mut seen = vec![false; 1 << 19];
        for column in 0..196_884u32 {
            let key = monster_column_foil_key(column);
            assert!(!seen[key as usize], "duplicate key for column {column}");
            seen[key as usize] = true;

            let block = column / 12;
            assert_eq!(foil_key_phase(key), column % 12);
            assert_eq!(foil_key_band(key), monster_band_of_block(block));
            let base = match foil_key_band(key) {
                FOIL_BAND_SYM_SQUARE => 0,
                FOIL_BAND_PAIR => SYM_SQUARE_SEAM_BLOCK,
                _ => PAIR_FRAME_SEAM_BLOCK,
            };
            assert_eq!(foil_key_block(key) + base, block);
        }
    }

    #[test]
    fn band_dispatch_matches_griess_band_sizes() {
        let mut counts = [0u32; 3];
        for block in 0..MONSTER_AEON_BLOCKS {
            counts[monster_band_of_block(block) as usize] += 1;
        }
        // 300 = 25·12, 98280 = 8190·12, 98304 = 8192·12 (griess_band_decomposition).
        assert_eq!(counts, [25, 8190, 8192]);
    }

    #[test]
    fn aeon_phase_clock_never_needs_mod_twelve() {
        let mut clock = AeonPhaseClock::from_tick(0);
        for tick in 0..100_000u64 {
            assert_eq!(clock.phase as u64, tick % 12, "tick = {tick}");
            assert_eq!(clock.block, tick / 12, "tick = {tick}");
            assert_eq!(clock.as_tick(), tick); // aeon_split_roundtrip
            assert_eq!(clock, AeonPhaseClock::from_tick(tick));
            clock = clock.tick();
        }
    }
}
